import okhttp3.Interceptor
import okhttp3.OkHttpClient
import okhttp3.Request
import okhttp3.logging.HttpLoggingInterceptor
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import retrofit2.http.GET
import retrofit2.http.Header
import retrofit2.http.Headers
import retrofit2.http.Path
import java.util.concurrent.TimeUnit

// Define API Service
interface ApiService {
    @GET("users/{id}")
    suspend fun getUserProfile(
        @Path("id") userId: String,
        @Header("Authorization") token: String
    ): UserProfile
}

// User Profile Data Class
data class UserProfile(val id: String, val name: String, val email: String)

// Environment Configuration
object EnvironmentConfig {
    const val DEV_BASE_URL = "https://dev.api.example.com/"
    const val STAGING_BASE_URL = "https://staging.api.example.com/"
    const val PROD_BASE_URL = "https://api.example.com/"
}

// OkHttp Client with TLS validation and logging
fun provideOkHttpClient(): OkHttpClient {
    val logging = HttpLoggingInterceptor().apply {
        level = HttpLoggingInterceptor.Level.BODY
    }

    return OkHttpClient.Builder()
        .addInterceptor(logging)
        .connectTimeout(30, TimeUnit.SECONDS)
        .readTimeout(30, TimeUnit.SECONDS)
        .writeTimeout(30, TimeUnit.SECONDS)
        .build()
}

// Retrofit Instance
fun provideRetrofit(baseUrl: String): Retrofit {
    return Retrofit.Builder()
        .baseUrl(baseUrl)
        .client(provideOkHttpClient())
        .addConverterFactory(GsonConverterFactory.create())
        .build()
}

// API Service Provider
object ApiServiceFactory {
    fun createService(environment: String): ApiService {
        val baseUrl = when (environment) {
            "dev" -> EnvironmentConfig.DEV_BASE_URL
            "staging" -> EnvironmentConfig.STAGING_BASE_URL
            "prod" -> EnvironmentConfig.PROD_BASE_URL
            else -> throw IllegalArgumentException("Invalid environment")
        }
        return provideRetrofit(baseUrl).create(ApiService::class.java)
    }
}

